insert into public.help_articles (article_type, category, title, sort_order, content) values
  ('faq', 'Getting Started & Roles', 'What is the Help Center, and what''s in it?', 0, '{"answer":"The Help Center is where you find answers without leaving the app: this FAQ, a library of step-by-step Job Aides for common workflows, a downloadable PDF user manual, and a support ticketing system for anything not covered here. Org admins, facility managers, trainers, and auditors reach it from /app/help; employees reach the same content from /me/help."}'::jsonb),
  ('faq', 'Getting Started & Roles', 'What are the six roles, and what does each one actually see?', 1, '{"answer":"platform_admin is CareMetric CareBase staff -- confined to /admin, with the only ability to author courses and quizzes. org_admin and facility_manager work in /app: org_admin sees every facility in the organization, facility_manager is scoped to the facility (or facilities) they''re assigned to. auditor gets the same /app compliance views (dashboard, training matrix, reports, documents, audit log) with zero ability to create, edit, or delete anything -- it''s read-only by database policy, not just hidden buttons. trainer works in /trainer: scheduling and running live classes, monitoring retraining, and read access to facilities/employees. employee is self-service in /me: their own training records, assigned courses, certificates, credentials, schedule, and documents."}'::jsonb),
  ('faq', 'Getting Started & Roles', 'What''s the difference between org_admin and facility_manager?', 2, '{"answer":"org_admin is the organization-wide administrator: every facility, plus org-only tools like Users, Settings, and deleting training plans. facility_manager has nearly the same day-to-day toolset -- employees, training, courses, scheduling, incidents, and more -- but scoped to just the facility or facilities they''re assigned to. If you manage a single building, you''ll likely be a facility_manager; if you oversee the whole organization, you''re an org_admin."}'::jsonb),
  ('faq', 'Getting Started & Roles', 'I just set up my organization -- where do I start?', 3, '{"answer":"Self-service signup always creates a brand-new organization with you as its org_admin. From there: add your facilities, bring in your employee roster (one at a time or by CSV import), configure the training types and credential requirements your license type needs, and set up shift patterns if you''re using scheduling. Alerts, the training matrix, and the compliance binder all populate automatically once employees and their training records exist."}'::jsonb),
  ('faq', 'Employees & Training Records', 'How do I add an employee, and what do I need on hand?', 4, '{"answer":"Go to Employees and click Add Employee. You''ll need their name, contact info, job title, facility, hire date, and status. Two flags matter for compliance: whether they administer medications (drives medication-administration and diabetes-education tracking) and worker type -- regular, agency, substitute, or volunteer, since agency/substitute/volunteer staff get a faster, rapid-orientation checklist instead of the standard one."}'::jsonb),
  ('faq', 'Employees & Training Records', 'Can I bring in my whole existing roster instead of typing employees in one at a time?', 5, '{"answer":"Yes. The Employees page has a bulk CSV import that runs under your own login (organization scoping and RLS still apply exactly as if you''d entered each employee by hand), and it reports back row-by-row which employees imported successfully and which rows had errors so you can fix and re-upload just those."}'::jsonb),
  ('faq', 'Employees & Training Records', 'What do the training record statuses -- compliant, due soon, expired, missing -- actually mean?', 6, '{"answer":"Compliant means the record is current. Due soon means it''s still valid today but will expire inside the training type''s warning window, so it counts as \"currently authorized\" everywhere the app checks that (like Who Can Pass Meds Today). Expired means the deadline has passed, and missing means no record exists at all for a requirement that applies to that employee. Only expired and missing disqualify someone from being considered currently compliant."}'::jsonb),
  ('faq', 'Employees & Training Records', 'Where do I see one employee''s full compliance picture in one place?', 7, '{"answer":"Open their record from the Employees list. Employee Detail shows their training records, credentials, practicums, onboarding checklist, retention check-ins, and notes side by side -- it''s the fastest way to answer \"is this person actually current on everything\" without hunting across separate pages."}'::jsonb),
  ('faq', 'Courses & Quizzes', 'Who can create or edit courses and quizzes?', 8, '{"answer":"Course and quiz authoring is platform_admin-exclusive -- creating or editing courses, course versions, content blocks, quizzes, questions, and answers. Org admins, facility managers, and trainers can browse the full course catalog and assign courses to employees, but they can''t change course content itself. Once a course version is published, its content is locked and can''t be edited, even by a platform admin, without creating a new version."}'::jsonb),
  ('faq', 'Courses & Quizzes', 'How do I assign a course to an employee?', 9, '{"answer":"Go to Course Assignments, click Assign Course, and pick the employee, course, and (optionally) a due date. You can also skip individual assignment entirely by building a Training Plan and applying it to one or more employees at once -- that creates the same course assignments in bulk plus tracks any non-course training requirements bundled into the plan."}'::jsonb),
  ('faq', 'Courses & Quizzes', 'How does quiz grading work -- can an employee retake a quiz if they don''t pass?', 10, '{"answer":"Grading happens server-side, not in the browser -- an employee''s score and whether each answer was correct are never client-writable, so results can''t be tampered with. Each quiz has its own passing score and either a fixed number of attempts or unlimited attempts, both set when the quiz was built; if attempts remain, the employee can retake it immediately from the course."}'::jsonb),
  ('faq', 'Courses & Quizzes', 'What''s the difference between a Training Plan and a single Course Assignment?', 11, '{"answer":"A Course Assignment is one course given to one employee. A Training Plan is a reusable bundle of courses and/or training-type requirements -- build it once (say, a New Hire Onboarding plan), then apply it to any employee to create every course assignment in the bundle and start tracking every non-course requirement as pending, all in one action instead of assigning each piece separately."}'::jsonb),
  ('faq', 'Courses & Quizzes', 'Do employees need to install anything to take courses?', 12, '{"answer":"No. Employees sign in at /me/courses in any browser, open an assigned course, work through its lessons and any attached video or documents, take the quiz if there is one, and download their certificate afterward -- no app install, and no separate training vendor."}'::jsonb),
  ('faq', 'Scheduling', 'How does shift scheduling work in CareMetric CareBase?', 13, '{"answer":"Scheduling is basic shift scheduling, not tied to compliance qualification checks. First set up each facility''s units (wings), typical shift times, and each employee''s usual recurring pattern by day of week under Shifts, Units & Patterns. Then create a Schedule for a period (7 or 14 days), and either build it by hand or use Auto-Fill to populate it from everyone''s typical pattern."}'::jsonb),
  ('faq', 'Scheduling', 'What does "Auto-Fill from Typical Patterns" actually do?', 14, '{"answer":"It populates a draft schedule using every employee''s saved recurring shift/unit pattern, skipping any date where that employee already has a shift entered manually -- manual entries always win. If it created something wrong, Clear Auto-Fill removes only the untouched auto-generated rows, leaving any manual edits you''ve made in place."}'::jsonb),
  ('faq', 'Scheduling', 'Why can''t my employee see their shifts under My Schedule?', 15, '{"answer":"Employees can only see shifts on a schedule that''s been Published. A draft schedule -- even one that''s fully auto-filled -- stays invisible to employees until you publish it from Schedule Detail; move it back to draft any time you need to bulk-edit or re-run Auto-Fill."}'::jsonb),
  ('faq', 'Scheduling', 'Can one employee be scheduled at two facilities on the same day?', 16, '{"answer":"Not currently -- an employee is capped at one shift per calendar date across every facility they''re assigned to, so there''s no double-booking and no same-day float between two locations. An employee can still be assigned to work at more than one facility over time, just not on the same date."}'::jsonb),
  ('faq', 'Compliance & Alerts', 'What triggers a compliance alert?', 17, '{"answer":"Alerts fire for the events that put you at survey risk: training due soon or expired, missing documents, expiring certificates or credentials, practicums due soon or expired, a reported incident, a policy attestation due soon, and (for personal care homes/assisted living) resident compliance items coming due. Each alert carries a severity -- critical, warning, or info -- so you can triage what needs attention first."}'::jsonb),
  ('faq', 'Compliance & Alerts', 'What''s the difference between "due soon" and "expired" everywhere in the app?', 18, '{"answer":"Due soon means the requirement is still valid today but falls inside its warning window before the deadline -- it still counts as currently compliant everywhere that matters, like medication-administration authorization. Expired means the deadline has already passed. The warning window''s default lead time is configurable per organization in Settings."}'::jsonb),
  ('faq', 'Compliance & Alerts', 'Who can dismiss or resolve an alert, and does that change the underlying record?', 19, '{"answer":"Alerts have their own status -- open, dismissed, or resolved -- separate from the training record, credential, or practicum that generated them. Dismissing or resolving an alert just clears it from your open queue; it doesn''t retroactively mark the underlying requirement as complete. If the requirement itself is still outstanding, a fresh alert can be generated again."}'::jsonb),
  ('faq', 'Compliance & Alerts', 'How do I get a quick read on whether my facility is survey-ready right now?', 20, '{"answer":"Inspection Readiness gives you a citation-weighted readiness score per facility plus a mock entrance-conference checklist that pulls live from your training, credential, background-check, inspection, incident, and policy-attestation data. It''s modeled on general DHS entrance-conference practice, not a verbatim reproduction of the current DHS guide, so keep your own copy on hand to compare exact wording before a real inspection."}'::jsonb),
  ('faq', 'Documents & Policies', 'What''s the difference between Documents and Policy Documents?', 21, '{"answer":"Documents is where you upload and manage individual files -- certificates, training rosters, practicum forms, transcripts, and competency attachments -- tied to a specific employee or facility. Policy Documents is a separate module for versioned organizational policies (like a Resident Rights Policy) with formal, ESIGN/UETA-compliant attestation campaigns that track who has read and signed off on each version."}'::jsonb),
  ('faq', 'Documents & Policies', 'How does policy attestation work?', 22, '{"answer":"Create the policy document, upload and publish a version, then launch an attestation campaign against it -- that assigns the requirement to the roster you target and tracks each person''s signature with a due date. Anyone assigned an attestation sees it under My Attestations and signs off there; overdue attestations show up as alerts and on the Inspection Readiness checklist."}'::jsonb),
  ('faq', 'Documents & Policies', 'How securely are uploaded documents stored?', 23, '{"answer":"Every document lives in private Supabase Storage, split across separate buckets by type (external uploads, sign-in sheets, competency attachments, and more), and is only ever retrieved through a short-lived signed link -- there''s no public URL for any of it. Deleting an uploaded training document is restricted to org_admin and facility_manager; even the employee who uploaded it can''t delete it themselves."}'::jsonb),
  ('faq', 'Documents & Policies', 'Can employees upload their own documents, like an external certificate?', 24, '{"answer":"Yes -- employees can upload documents such as an external certificate for training they completed outside the platform. It doesn''t automatically count toward compliance, though: it lands in Pending Approvals, where an org admin or facility manager reviews it and confirms (or declines) whether it satisfies a training requirement before it affects that employee''s compliance status."}'::jsonb),
  ('faq', 'Residents & Facility Compliance', 'What does the Residents module actually track?', 25, '{"answer":"For personal care homes and assisted living residences, Residents tracks RASP/ASP compliance deadlines by resident -- from preadmission screening through the annual reassessment cycle -- plus contacts and supports, a compliance checklist, digital assessment forms, and related documents. It''s explicitly compliance-deadline tracking, not a charting or care-plan system."}'::jsonb),
  ('faq', 'Residents & Facility Compliance', 'Does CareMetric CareBase store clinical charting or care plans for residents?', 26, '{"answer":"No. The Residents module is scoped to compliance recordkeeping -- assessment/support-plan deadlines, contacts, and the documents that prove those deadlines were met -- not day-to-day clinical charting or care planning. That''s a deliberate boundary, kept out of scope on purpose."}'::jsonb),
  ('faq', 'Residents & Facility Compliance', 'How do incidents and cited DHS violations connect to residents?', 27, '{"answer":"Incidents & Complaints lets you log and investigate reportable events, track required notifications (state hotline, family/guardian, law enforcement, licensing agency), and attach corrective actions -- some incidents reference a specific resident. Violations & Plans of Correction is separate: it''s where you enter what a DHS inspection actually cited and manage that citation''s Plan of Correction through to verification, whether or not a specific resident was involved."}'::jsonb),
  ('faq', 'Residents & Facility Compliance', 'What''s the Inspection Readiness score based on, and is it a live DHS feed?', 28, '{"answer":"It''s a weighted rollup of your own compliance data -- training, credentials, background checks, inspection items, incidents, and policy attestations -- grouped by DHS citation topic and weighted by a default per-topic planning weight. It is not a live BHSL citation-frequency feed; the weighting is a planning aid, not a prediction of what a real survey will cite."}'::jsonb),
  ('faq', 'Credentials & Background Checks', 'What kinds of credentials can I track on an employee?', 29, '{"answer":"Credentials & Clearances covers Act 34 criminal history, Act 73 FBI fingerprint, and Act 33 child abuse clearances, RN/LPN licenses, Nurse Aide Registry status, TB screening, immunization records, I-9 employment eligibility, and a catch-all Other category -- each with its own expiration tracking and status."}'::jsonb),
  ('faq', 'Credentials & Background Checks', 'How does the OAPSA provisional-employment countdown work?', 30, '{"answer":"Background Checks tracks whether an employee has been a PA resident for the prior two years, since that determines whether they can start work provisionally before clearances come back and how many days they get: your organization''s configured provisional window (30 days for residents, 90 for non-residents, by default) counts down from the provisional start date, with a clear warning once only a few days remain."}'::jsonb),
  ('faq', 'Credentials & Background Checks', 'What is Exclusion Screening, and why do some matches turn out to be false positives?', 31, '{"answer":"Exclusion Screening checks your roster against the OIG LEIE and SAM.gov federal exclusion lists using fuzzy name matching, which can surface matches that are actually a different person with a similar name. Every match lands in a Pending Review queue where you confirm it as a real exclusion or mark it a false positive -- nothing is auto-actioned. You can also trigger a manual re-scan of your whole roster at any time."}'::jsonb),
  ('faq', 'Credentials & Background Checks', 'Who can see credential and background-check data?', 32, '{"answer":"It''s more restricted than most compliance data: org_admin, facility_manager, and auditor can see it, but trainer cannot -- clearance and license information is treated as more sensitive than ordinary training records."}'::jsonb),
  ('faq', 'Credentials & Background Checks', 'What does the Administrator Qualification module cover?', 33, '{"answer":"For personal care homes and assisted living residences, it tracks the administrator''s qualification path -- the 100-hour DHS-approved administrator course or the NHA license exemption -- the written regional-office verification submission, and the rolling 24-hour annual continuing-education requirement, with the source and evidence captured for each CE entry."}'::jsonb),
  ('faq', 'Reports & Compliance Binder', 'What reports can I run?', 34, '{"answer":"Reports covers compliance summaries and facility scores, expired/due-soon/overdue training, medication administration training, the training matrix, practicum status (including the annual practicum report), training hours (annual and detail), trainer certification status, new-employee and full transcripts, expiring certifications, missing documents and a document audit, credential and clearance status, incident logs and notification registers, and inspection/equipment compliance -- filterable by facility and exportable."}'::jsonb),
  ('faq', 'Reports & Compliance Binder', 'How is the Compliance Binder different from just running a report?', 35, '{"answer":"A report is a table you view, print, or export as CSV. The Compliance Binder is a single generated PDF that pulls a facility''s roster, staff training compliance, practicums, certificates, and open alerts together into one survey-ready packet in one click -- built fresh from current data every time you generate it, not a print-to-PDF of a report screen."}'::jsonb),
  ('faq', 'Reports & Compliance Binder', 'How long is the Compliance Binder download link good for?', 36, '{"answer":"The generated PDF is delivered through a short-lived signed link, not a permanent public URL, so it typically expires within a few minutes. If it expires before you''ve downloaded it, just generate a fresh binder -- it only takes a few seconds."}'::jsonb),
  ('faq', 'Reports & Compliance Binder', 'Can an auditor run reports and generate the binder themselves, or do they have to ask an admin?', 37, '{"answer":"Auditors can run reports and generate the compliance binder themselves -- both are part of the read-only compliance view auditors get alongside org_admin and facility_manager. They just can''t create, edit, or delete the underlying records those reports summarize."}'::jsonb),
  ('faq', 'Support & Account', 'How do I contact support?', 38, '{"answer":"From the Help Center, open the Submit a Ticket tab, pick a category (general question, technical issue, billing, training content, account access, or feature request) and a priority, describe what''s going on, and submit. Your message becomes the first entry in a ticket thread you can keep replying to."}'::jsonb),
  ('faq', 'Support & Account', 'How do I check the status of a ticket I already submitted?', 39, '{"answer":"Open My Tickets in the Help Center to see every ticket you''ve filed and its current status -- open, in progress, resolved, or closed. You''ll get an in-app notification the moment support replies or changes your ticket''s status, and you can reply right in the thread or close/reopen the ticket yourself once it''s settled."}'::jsonb),
  ('faq', 'Support & Account', 'Where do I find the full PDF user manual?', 40, '{"answer":"The Help Center links directly to a downloadable PDF user manual alongside the FAQ and Job Aides, for anyone who wants the complete walkthrough in one document or needs an offline copy."}'::jsonb),
  ('faq', 'Support & Account', 'How do I reset my password or update my account details?', 41, '{"answer":"Use the Forgot Password link from the login screen to reset your password. For changes to your name, role, or organization, ask your org_admin or facility_manager -- email address changes specifically require an admin action, so contact platform support if you need yours updated."}'::jsonb),
  ('job_aide', 'Employees & Onboarding', 'Add a New Employee', 0, '{"summary":"Create a single employee record with the details compliance tracking depends on.","audience":["org_admin","facility_manager"],"steps":["Go to Employees and click Add Employee.","Enter first name, last name, email, phone, job title, and department.","Select the employee''s facility and enter their hire date.","Set Worker Type -- regular, agency, substitute, or volunteer -- since agency/substitute/volunteer staff get the faster rapid-orientation checklist instead of the standard one.","Check Administers Medications if this employee gives or assists with medications; this drives medication-administration and diabetes-education tracking and determines whether they appear on the Who Can Pass Meds Today roster.","Enter Scheduled Hours Per Week if known -- it drives the 40-scheduled-hour orientation deadline for new hires.","Set Status to Active and click Save."],"tips":["You can always edit these fields later from the employee''s own record if something changes.","If you''re onboarding more than a handful of employees at once, use Bulk-Import an Employee Roster via CSV instead."],"relatedRoute":{"label":"Go to Employees","href":"/app/employees"}}'::jsonb),
  ('job_aide', 'Employees & Onboarding', 'Bulk-Import an Employee Roster via CSV', 1, '{"summary":"Onboard an entire facility''s staff in minutes instead of entering employees one at a time.","audience":["org_admin","facility_manager"],"steps":["Go to Employees and click Upload (the bulk import button).","Download the CSV template if you need the expected column headers.","Fill in one row per employee and upload the completed file.","Wait for the import to finish -- it processes under your own login, so the same organization scoping and permissions apply as if you''d entered each row by hand.","Review the row-by-row results: each row reports success or a specific error.","Fix and re-upload only the rows that failed; successful rows are already saved and won''t be duplicated."],"tips":["Double-check facility names and email addresses before uploading -- most row failures come from a typo in one of those two fields."],"relatedRoute":{"label":"Go to Employees","href":"/app/employees"}}'::jsonb),
  ('job_aide', 'Employees & Onboarding', 'Invite a New User Account', 2, '{"summary":"Give someone sign-in access with the right role, separate from creating their employee record.","audience":["org_admin","facility_manager"],"steps":["Go to Users and click Add User.","Enter their name and email, then choose a role -- facility_manager can only create trainer or employee accounts; org_admin can create any non-platform_admin role in the organization.","If applicable, link the account to an existing employee record so their training data shows up under their own login.","Save -- the new user receives access to sign in under their assigned role."],"tips":["An employee record and a user login are two different things: an employee can exist without ever getting sign-in access, and every user account must belong to exactly one role.","Email address changes on an existing account require an admin action -- edit the user from Users, or contact platform support if you can''t."],"relatedRoute":{"label":"Go to Users","href":"/app/users"}}'::jsonb),
  ('job_aide', 'Training & Courses', 'Assign a Course to an Employee', 3, '{"summary":"Give one employee a specific course to complete, with an optional due date.","audience":["org_admin","facility_manager","trainer"],"steps":["Go to Course Assignments and click Assign Course.","Select the employee and the course from the catalog.","Optionally pick a specific course version (otherwise the course''s current published version is used).","Set a due date if this assignment needs one -- assignments without a due date still show up under the employee''s My Courses, just not on dashboard deadline widgets.","Save. The assignment starts as Assigned and moves to In Progress, Completed, or Overdue automatically as the employee works through it."],"tips":["For onboarding or recurring curricula, build a Training Plan instead and apply it to employees in bulk rather than assigning course by course."],"relatedRoute":{"label":"Go to Course Assignments","href":"/app/course-assignments"}}'::jsonb),
  ('job_aide', 'Training & Courses', 'Build a Quiz for a Course', 4, '{"summary":"Author quiz questions, answers, passing score, and attempt limits for a course (platform admin only).","audience":["platform_admin"],"steps":["From the course''s detail page, open its quiz (or create one for a course version that doesn''t have one yet).","Click Add Question and enter the question text and its answer options.","Mark the correct answer -- grading is server-side and based on this flag, so it can''t be spoofed by a client later.","Set the quiz''s passing score percentage and either a maximum number of attempts or unlimited attempts.","Repeat for each question, then save."],"tips":["Once the parent course version is published, its quiz is locked -- create a new course version if you need to change questions after that point.","Course and quiz authoring is platform_admin-exclusive; org_admin, facility_manager, and trainer can browse and assign courses but cannot edit their content."],"relatedRoute":{"label":"Go to Courses (Admin)","href":"/admin/courses"}}'::jsonb),
  ('job_aide', 'Training & Courses', 'Create a Training Plan and Apply It to Employees', 5, '{"summary":"Bundle courses and training-type requirements into a reusable curriculum, then apply it in bulk.","audience":["org_admin","trainer"],"steps":["Go to Training Plans and click New Plan.","Name the plan (for example, New Hire Onboarding) and add a description.","Expand the plan and click Add Item for each course or legacy training type it should include, marking each as required or optional.","Reorder items with the up/down arrows if the sequence matters.","Click Apply to Employee(s), search and select who the plan applies to, and confirm.","Review the summary: it reports how many course assignments were created and how many training-type requirements are now tracked as pending for each employee."],"tips":["facility_manager can view and browse training plans but can''t create, edit, or apply them -- that''s org_admin and trainer only.","Removing an item from a plan template later doesn''t undo assignments already created from a previous Apply run."],"relatedRoute":{"label":"Go to Training Plans","href":"/app/training-plans"}}'::jsonb),
  ('job_aide', 'Training & Courses', 'Take an Assigned Course', 6, '{"summary":"Work through a course assigned to you, lesson by lesson, from any browser.","audience":["employee"],"steps":["Go to My Courses and pick the course you want to start -- it lists every course assigned to you, whether or not it has a due date.","Click into the course to open it; this takes you to the course-taking view.","Work through each lesson in order, including any attached video or reading material.","If the course has a quiz, it appears once you''ve completed the lessons.","Your progress and completion status update automatically as you go."],"tips":["No software install is required -- courses run entirely in your browser."],"relatedRoute":{"label":"Go to My Courses","href":"/me/courses"}}'::jsonb),
  ('job_aide', 'Training & Courses', 'Take a Quiz and Review Your Score', 7, '{"summary":"Complete a course''s quiz and see whether you passed.","audience":["employee"],"steps":["From the course, open its quiz -- you''ll see the number of questions, the passing score, and how many attempts you''re allowed (or if attempts are unlimited).","Click to start, then answer each question.","Submit the quiz when finished.","Review your score and, for any missed questions, the correct answer shown in the review.","If you didn''t pass and attempts remain, retake the quiz directly from the same screen."],"tips":["Grading happens on the server the moment you submit, so your score is final and can''t be edited after the fact."],"relatedRoute":{"label":"Go to My Courses","href":"/me/courses"}}'::jsonb),
  ('job_aide', 'Training & Courses', 'View and Download Your Certificate', 8, '{"summary":"Get a downloadable, verifiable PDF certificate for a course you completed.","audience":["employee"],"steps":["Go to My Certificates.","Find the certificate for the course you completed.","Click Download to generate the PDF -- it opens in a new tab once generated.","Note the certificate''s public verification link if you need to share proof of completion with an employer or a surveyor."],"tips":["A certificate that shows as expired here means its renewal window has passed -- check My Courses for a renewal assignment."],"relatedRoute":{"label":"Go to My Certificates","href":"/me/certificates"}}'::jsonb),
  ('job_aide', 'Training & Courses', 'Approve an Externally-Uploaded Certificate', 9, '{"summary":"Review a certificate an employee uploaded from outside the platform and decide whether it counts toward compliance.","audience":["org_admin","facility_manager"],"steps":["Go to Pending Approvals.","Under New Submissions, review each externally uploaded certificate -- who submitted it, when, and which employee it''s for.","Open the document to verify it, then decide: link it to a training requirement and approve, or decline it.","Check the Pending Review tab for records already linked to a training requirement that still need a final compliance decision.","Confirm your decision -- approved records update the employee''s training record status immediately."],"tips":["Use the \"hide documents older than\" filter to focus the queue on recent submissions if it gets long."],"relatedRoute":{"label":"Go to Pending Approvals","href":"/app/pending-approvals"}}'::jsonb),
  ('job_aide', 'Training & Courses', 'Schedule a Live Training Class and Capture Sign-In', 10, '{"summary":"Run an instructor-led session and record attendance so it counts toward compliance like an online course.","audience":["trainer","org_admin","facility_manager"],"steps":["Go to Training Classes and click New Class.","Enter the class name, training type, date, and facility, then save.","Add attendees from the class detail page.","For in-person check-in, open QR Check-In and let staff scan the code with their phone to check in, then scan again to check out -- it rotates automatically every 30 seconds for security.","As a paper backup, print the Notice of Staff Meeting, which includes a long-lived QR code plus a paper sign-in table.","Once the class is done, use Upload Roster to attach the completed paper sign-in sheet if you used one.","Mark the class Completed once attendance is finalized."],"tips":["Kiosk Mode turns a shared tablet or computer into a stationary check-in station for the whole session."],"relatedRoute":{"label":"Go to Training Classes","href":"/trainer/classes"}}'::jsonb),
  ('job_aide', 'Scheduling', 'Set Up Facility Shifts, Units & Typical Patterns', 11, '{"summary":"Configure the building blocks scheduling needs before you can build or auto-fill a schedule.","audience":["org_admin","facility_manager"],"steps":["Go to Schedule and click Shifts, Units & Patterns.","Select the facility you''re configuring.","Under Units & Wings, add each unit or wing employees can be scheduled to.","Under Shift Types, add the typical shift time templates your facility uses (for example, Day, Evening, Night).","Under Typical Patterns, set each employee''s usual recurring shift and unit by day of week.","Save -- this setup is what Auto-Fill draws from when building a new schedule."],"tips":["Do this once per facility; you won''t need to repeat it unless shift times or an employee''s typical pattern changes."],"relatedRoute":{"label":"Go to Shifts, Units & Patterns","href":"/app/schedule/setup"}}'::jsonb),
  ('job_aide', 'Scheduling', 'Build and Publish a Weekly Schedule', 12, '{"summary":"Create a draft schedule, auto-fill it, make manual adjustments, then publish it so employees can see it.","audience":["org_admin","facility_manager"],"steps":["Go to Schedule and click New Schedule.","Select the facility, a start date, and a 7- or 14-day period length, then create it.","On the schedule''s detail page, click Auto-Fill from Typical Patterns to populate shifts from each employee''s saved pattern.","Make any manual edits needed -- manual entries are never overwritten by auto-fill, and Clear Auto-Fill only removes untouched auto-generated rows if you need to start over.","Click Publish once the schedule is final.","Use Move to Draft if you need to make further changes after publishing -- employees stop seeing it under My Schedule until it''s published again."],"tips":["An employee is capped at one shift per calendar date across every facility, so there''s no accidental double-booking."],"relatedRoute":{"label":"Go to Schedule","href":"/app/schedule"}}'::jsonb),
  ('job_aide', 'Scheduling', 'View Your Published Shifts', 13, '{"summary":"Check your upcoming work schedule once it''s been published.","audience":["employee"],"steps":["Go to My Schedule.","Review your upcoming published shifts by date and facility.","Contact your facility manager if a shift looks wrong -- shifts are managed centrally and aren''t self-editable."],"tips":["Only published schedules appear here; a schedule still in draft won''t show up even if it already has shifts entered."],"relatedRoute":{"label":"Go to My Schedule","href":"/me/schedule"}}'::jsonb),
  ('job_aide', 'Compliance Tracking', 'Set Up a Competency Template', 14, '{"summary":"Build a reusable checklist that evaluators fill out to verify an employee''s hands-on competency.","audience":["org_admin","trainer"],"steps":["Go to Competency Templates and click New Template.","Name the template (for example, Medication Administration Competency) and add a description of what it verifies and when to use it.","Click Items on the new template to open its checklist.","Add each checklist item as a short, observable statement (for example, \"Washes hands before administering medication\").","Reorder items with the up/down arrows if sequence matters, then close."],"tips":["A template can''t be deleted while any completed competency record still references it -- those records stay auditable."],"relatedRoute":{"label":"Go to Competency Templates","href":"/app/competency-templates"}}'::jsonb),
  ('job_aide', 'Compliance Tracking', 'Record a Competency Evaluation', 15, '{"summary":"Document that an evaluator observed an employee against a competency checklist and the result.","audience":["org_admin","facility_manager","trainer"],"steps":["Go to Competency Records and click New Record.","Select the employee, the competency template, and the evaluation date.","Go through each checklist item and mark it met, not met, or not applicable.","Set the overall result -- met, not met, or partial.","Save and, if required by your facility''s process, capture the evaluator''s signature."],"tips":["Use Who Can Pass Meds Today to see the combined effect of certification plus practicum plus competency status for medication-administering staff."],"relatedRoute":{"label":"Go to Competency Records","href":"/app/competency-records"}}'::jsonb),
  ('job_aide', 'Compliance Tracking', 'Log an Annual Medication Administration Practicum', 16, '{"summary":"Record a medication-administering employee''s annual hands-on practicum so their authorization stays current.","audience":["org_admin","facility_manager","trainer"],"steps":["Go to Practicums.","Click Add Practicum (or edit an existing one for the current year) and select the employee and practicum year.","Enter the completion date and who observed it, plus the due date and reminder window for the next one.","Record any additional observation windows or MAR-review checkpoints your facility''s process requires.","Save -- the practicum''s status (compliant, due soon, expired, or missing) recalculates from the due date and reminder window automatically."],"tips":["Practicum status is driven purely by the due date and reminder window you enter here -- it isn''t automatically derived from the completion date."],"relatedRoute":{"label":"Go to Practicums","href":"/app/practicums"}}'::jsonb),
  ('job_aide', 'Compliance Tracking', 'Check Who Can Pass Meds Today', 17, '{"summary":"See a live, combined view of medication-administration authorization across your staff.","audience":["org_admin","facility_manager","trainer"],"steps":["Go to Who Can Pass Meds Today.","Optionally filter to a single facility.","Review each medication-administering employee''s certification status, current-year practicum status, and insulin/diabetes-education authorization side by side.","Check the Authorized Today column for the combined answer -- it only reads Yes if both certification and practicum are currently valid (compliant or due soon)."],"tips":["Only employees with Administers Medications checked on their employee record appear on this roster -- if someone''s missing, check that flag first."],"relatedRoute":{"label":"Go to Who Can Pass Meds Today","href":"/app/med-admin-roster"}}'::jsonb),
  ('job_aide', 'Compliance Tracking', 'File an Incident or Complaint', 18, '{"summary":"Log a reportable event, track required notifications, and manage its investigation through to a final report.","audience":["org_admin","facility_manager"],"steps":["Go to Incidents & Complaints and click New Incident.","Select the incident type (for example, medication error, significant injury, elopement, abuse allegation) and severity.","Enter the facility, date/time, location detail, and resident identifier if applicable.","Save, then open the incident''s detail page to add the narrative, staff involved, and any required notifications (state hotline, family/guardian, law enforcement, licensing agency).","Add corrective actions as they''re identified and upload supporting documents.","Generate the final report once the investigation is complete."],"tips":["This module is intentionally restricted to org_admin and facility_manager -- trainer and self-service employee access are both excluded given the sensitivity of incident data."],"relatedRoute":{"label":"Go to Incidents & Complaints","href":"/app/incidents"}}'::jsonb),
  ('job_aide', 'Compliance Tracking', 'Track a Cited DHS Violation Through Its Plan of Correction', 19, '{"summary":"Enter a citation from a DHS inspection and manage its Plan of Correction through to verification.","audience":["org_admin","facility_manager"],"steps":["Go to Violations & Plans of Correction and click New Violation.","Select the facility, citation topic, and severity, and enter the citation reference and description.","Set the Plan of Correction due date.","Open the violation''s detail page to add corrective actions with owners and due dates as they''re worked.","Upload evidence documents -- photos, corrected policies, retraining records -- supporting each corrective action.","Move the status forward from open, to POC submitted, to corrected, to verified as the correction is confirmed."],"tips":["Like Incidents, this module is org_admin/facility_manager only -- a cited violation and its POC are treated as an org-compliance matter, not a trainer- or self-service-facing one."],"relatedRoute":{"label":"Go to Violations","href":"/app/violations"}}'::jsonb),
  ('job_aide', 'Compliance Tracking', 'Add a Resident and Track RASP/ASP Deadlines', 20, '{"summary":"Track a personal care home or assisted living resident''s assessment and support-plan compliance deadlines.","audience":["org_admin","facility_manager"],"steps":["Go to Residents and click Add Resident.","Enter admission date, room, and basic demographics.","Open the resident''s detail page to add contacts and supports (physician, dentist, case manager, designated person).","Complete the compliance checklist and any digital assessment forms your facility uses (RASP/ASP).","Upload supporting documents -- completed DHS forms, DME evidence -- to the resident''s Documents section.","Use Resident Compliance to see upcoming deadlines across every resident at a glance."],"tips":["This module tracks compliance deadlines only -- no charting or care-plan data is stored here."],"relatedRoute":{"label":"Go to Residents","href":"/app/residents"}}'::jsonb),
  ('job_aide', 'Compliance Tracking', 'Run the Inspection Readiness Score & Build an Entrance Packet', 21, '{"summary":"Get a live, citation-weighted readiness score per facility and a one-click entrance-conference packet.","audience":["org_admin","facility_manager","auditor"],"steps":["Go to Inspection Readiness and select a facility.","Review the citation-weighted readiness score and the topic-by-topic breakdown, sorted worst-performing first.","Work through the Mock Entrance Conference Checklist, which flags each area as Ready or Attention Needed based on your live data.","Click Generate Entrance Packet to produce a one-click PDF covering facilities, staff training, credentials, incidents, and inspection items.","Download the packet before its short-lived link expires; generate a fresh one any time."],"tips":["The checklist is modeled on general DHS entrance-conference practice, not a verbatim copy of the current DHS guide -- keep your own reference copy handy to compare exact wording."],"relatedRoute":{"label":"Go to Inspection Readiness","href":"/app/inspection-readiness"}}'::jsonb),
  ('job_aide', 'Compliance Tracking', 'Upload a Credential Document for an Employee', 22, '{"summary":"Attach the supporting document for a background clearance, license, or health screening.","audience":["org_admin","facility_manager"],"steps":["Go to Credentials & Clearances.","Find or add the employee''s credential entry (for example, Act 34 Criminal History Clearance, RN License, TB Screening).","Enter the issue and expiration dates.","Upload the supporting document to the credential record.","Save -- expiration status recalculates automatically overnight; set it manually only if you need to override the calculated value."],"tips":["This page is limited to org_admin, facility_manager, and auditor -- trainer doesn''t have access, since clearance data is treated as more sensitive than ordinary training records."],"relatedRoute":{"label":"Go to Credentials & Clearances","href":"/app/credentials"}}'::jsonb),
  ('job_aide', 'Documents & Policies', 'Publish a Policy Document and Run an Attestation Campaign', 23, '{"summary":"Roll out a versioned policy and formally track who has read and signed off on it.","audience":["org_admin","facility_manager"],"steps":["Go to Policies & Procedures and click New Policy Document.","Enter a title, category, and description, then create it.","Open the new policy document and upload a version, then publish it.","Click Campaigns and start a new attestation campaign against the published version, targeting the roster it applies to and setting a due date.","Monitor completion as employees sign off from their own My Attestations page."],"tips":["Attestation campaigns are ESIGN/UETA-compliant -- each signature is tied to the specific published version the employee actually attested to."],"relatedRoute":{"label":"Go to Policies & Procedures","href":"/app/policy-documents"}}'::jsonb),
  ('job_aide', 'Documents & Policies', 'Upload a Training Document or Certificate', 24, '{"summary":"Attach a certificate, roster, practicum form, transcript, or other supporting file to an employee or facility.","audience":["org_admin","facility_manager"],"steps":["Go to Documents and click Upload.","Select the facility and, if applicable, the specific employee this document belongs to.","Choose the document type -- certificate, roster, practicum form, transcript, external certificate, competency attachment, or other.","Select the file and upload it.","Verify it appears in the list, filtered by facility, employee, or document type as needed."],"tips":["Only org_admin and facility_manager can delete an uploaded document -- not even the employee who uploaded it can remove it themselves."],"relatedRoute":{"label":"Go to Documents","href":"/app/documents"}}'::jsonb),
  ('job_aide', 'Reports', 'Generate the Compliance Binder', 25, '{"summary":"Produce a single, survey-ready PDF covering a facility''s roster, training compliance, practicums, certificates, and open alerts.","audience":["org_admin","facility_manager","auditor"],"steps":["Go to Compliance Binder.","Click Generate Binder PDF.","Wait for generation to complete, then click Download PDF.","Download it promptly -- the link expires after a short window, so generate a new binder if it lapses before you''ve saved it."],"tips":["The binder is built fresh from current data every time -- there''s no stale cached version to worry about."],"relatedRoute":{"label":"Go to Compliance Binder","href":"/app/compliance-binder"}}'::jsonb),
  ('job_aide', 'Reports', 'Run a Compliance Report', 26, '{"summary":"Generate, view, print, or export a specific compliance report for your organization.","audience":["org_admin","facility_manager","auditor"],"steps":["Go to Reports.","Optionally filter to a single facility.","Use the category tabs (Compliance, Training, Practicum, Hours, Staff, Documents, Credentials, Incidents, and more) or search to find the report you want.","Click the report to generate and view it.","Use Export CSV to download the data, or print directly from the viewer."],"tips":["Reports respect the same role-based scoping as the rest of the app -- an org_admin sees every facility, a facility_manager only their own."],"relatedRoute":{"label":"Go to Reports","href":"/app/reports"}}'::jsonb),
  ('job_aide', 'Getting Help', 'Submit a Support Ticket', 27, '{"summary":"Reach support directly from inside the app for anything the FAQ and Job Aides don''t cover.","audience":["org_admin","facility_manager","trainer","auditor","employee"],"steps":["Open the Help Center.","Click the Submit a Ticket tab.","Enter a subject and choose a category -- general question, technical issue, billing, training content, account access, or feature request.","Choose a priority -- low, normal, high, or urgent.","Describe the issue in the message field and submit.","Your ticket appears under My Tickets, where you can keep replying in the same thread."],"tips":["You''ll get an in-app notification the moment support replies, so there''s no need to keep checking back manually."],"relatedRoute":{"label":"Go to Help Center","href":"/app/help"}}'::jsonb),
  ('job_aide', 'Getting Help', 'Check the Status of a Support Ticket', 28, '{"summary":"Track replies and resolution progress on a ticket you''ve already submitted.","audience":["org_admin","facility_manager","trainer","auditor","employee"],"steps":["Open the Help Center and go to My Tickets.","Find your ticket and check its status -- open, in progress, resolved, or closed.","Open the ticket to read the full message thread, including any support replies.","Reply in the thread if you need to add information.","Once your issue is settled, close the ticket yourself -- or reopen a resolved/closed ticket if the issue comes back."],"tips":["A ticket automatically moves from open to in progress the moment support sends its first reply."],"relatedRoute":{"label":"Go to My Tickets","href":"/app/help"}}'::jsonb);
